-- ملء محتوى عنقود "الطب والأحكام الشرعية" (tibb-ahkam-shariyya) — أربعة
-- تصنيفات فرعية، كلها draft (استنفاد كامل للعنقود): التداوي، النوازل
-- الطبية المعاصرة، أحكام المريض، أخلاقيات الممارسة الطبية.
-- كل تصنيف يحصل على درس واحد (lessons + lesson_sections +
-- lesson_citations)، بنفس أسلوب دروس madhahib-fiqh-muqaran/wilaya-islamiyya
-- (تعريفي موجز: قسم body + قسم examples).
-- المصادر المعتمدة: الطب النبوي لابن قيم الجوزية (التداوي)، قرارات مجمع
-- الفقه الإسلامي الدولي — القرار رقم 26 (1/4) بشأن انتفاع الإنسان بأعضاء
-- جسم إنسان آخر، جدة 1408هـ/1988م (النوازل الطبية)، الفقه الإسلامي
-- وأدلته لوهبة الزحيلي (أحكام المريض)، أحكام الجراحة الطبية والآثار
-- المترتبة عليها لمحمد المختار الشنقيطي (أخلاقيات الممارسة الطبية).
-- حديثان استُشهد بهما، تحقَّقا حرفياً عبر WebSearch قبل الإدراج (كلاهما
-- صحيح من الصحيحين): "ما أنزل الله داء إلا أنزل له شفاء" (رواه البخاري
-- 5678 عن أبي هريرة)، و"من ستر مسلمًا ستره الله في الدنيا والآخرة" (رواه
-- مسلم 2699 عن أبي هريرة).
-- آيتان تحقَّقتا حرفياً محلياً من artifacts/majalis/public/data/quran
-- عبر حقل numberInSurah: البقرة 173 (الضرورة)، البقرة 184 (رخصة فطر
-- المريض).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الأربعة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) التداوي
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='5e062cd0-f3f4-435d-82d0-4cd4dde5527e' AND title='حكم التداوي في الشريعة الإسلامية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حكم التداوي في الشريعة الإسلامية', 'تعريف موجز بحكم التداوي عند الفقهاء وعلاقته بالتوكل على الله', '5e062cd0-f3f4-435d-82d0-4cd4dde5527e', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'حكم التداوي بين الإباحة والاستحباب والوجوب', 'التداوي هو طلب الشفاء من المرض بتناول الدواء أو الخضوع للعلاج بأنواعه المشروعة. اختلف الفقهاء في حكمه الأصلي على أقوال: فذهب جمهور الفقهاء إلى أن الأصل فيه الإباحة، لأنه من الأخذ بالأسباب المأذون فيها شرعًا. وذهب الشافعية وكثير من الحنابلة إلى استحبابه لثبوت الأمر به في أحاديث متعددة، مع كونه ليس واجبًا في أصله. ويتفق الفقهاء على أنه يعتريه التكليف الخماسي بحسب الأحوال: فيجب إذا توقفت عليه حياة النفس أو خشي من تركه الهلاك أو تلف عضو، ويستحب إذا كان المرض غير مخوف ورجي نفعه، ويكره أو يحرم إذا كان الدواء محرمًا بذاته كالخمر دون ضرورة ملجئة، ويباح فيما عدا ذلك. ولا يتنافى التداوي مع التوكل على الله، بل هو من كمال التوكل، إذ التوكل هو الاعتماد على الله مع الأخذ بالأسباب المشروعة، لا ترك الأسباب بالكلية.', 1),
    (v_lesson, 'examples', 'أصل الأمر بالتداوي من السنة', 'قال النبي صلى الله عليه وسلم: «ما أنزل الله داءً إلا أنزل له شفاءً» (رواه البخاري 5678 عن أبي هريرة رضي الله عنه)، وهو الأصل النبوي الذي بُني عليه مشروعية التداوي وطلب العلاج، إذ أخبر النبي صلى الله عليه وسلم أن كل داء له دواء قدّره الله وأنزله، وإنما يفتقر الوصول إليه إلى بذل السبب من طلب العلم بالطب والبحث عن الدواء.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الطب النبوي — ابن قيم الجوزية', 1);
  END IF;

  -- 2) النوازل الطبية المعاصرة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='2fa6b72a-2c47-4b37-bb5c-f4f744a1fbe7' AND title='منهج التعامل مع النوازل الطبية المعاصرة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('منهج التعامل مع النوازل الطبية المعاصرة', 'تعريف موجز بالنوازل الطبية المعاصرة وضوابط الاجتهاد الجماعي فيها', '2fa6b72a-2c47-4b37-bb5c-f4f744a1fbe7', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'ضوابط الاجتهاد في النوازل الطبية', 'النوازل الطبية المعاصرة هي المسائل المستجدة التي أفرزها التقدم الطبي الحديث ولم يتكلم فيها الفقهاء المتقدمون بأعيانها، كنقل الأعضاء وزراعتها، وتحديد لحظة الموت الدماغي، والتلقيح الصناعي داخل الرحم الزوجي، والفحص الجيني قبل الزواج أو الحمل، والاستنساخ، وغيرها. ولمعالجة هذه النوازل اعتمد أهل العلم منهجًا مجمعيًا يقوم على: أولاً، تصوير المسألة الطبية تصويرًا دقيقًا بالاستعانة بأهل الاختصاص الطبي قبل الحكم عليها، فلا يصح الحكم على مسألة طبية دون فهم حقيقتها. ثانيًا، ردّها إلى القواعد الفقهية الكلية المحكمة كقاعدة "الضرورات تبيح المحظورات" وقاعدة "الحاجة تنزل منزلة الضرورة" وقاعدة "درء المفاسد مقدم على جلب المصالح". ثالثًا، اعتماد الاجتهاد الجماعي عبر المجامع الفقهية المتخصصة بدل الاجتهاد الفردي، نظرًا لتشعب هذه المسائل وحاجتها إلى خبرات متعددة. رابعًا، مراعاة المآلات والآثار المترتبة على كل حكم قبل إصداره، صيانة لمقاصد الشريعة في حفظ النفس والنسل والعقل.', 1),
    (v_lesson, 'examples', 'أصل قاعدة الضرورة من القرآن', 'قال تعالى: ﴿فَمَنِ ٱضْطُرَّ غَيْرَ بَاغٍ وَلَا عَادٍ فَلَآ إِثْمَ عَلَيْهِ﴾ (البقرة: 173)، وهي الآية التي استُنبطت منها القاعدة الفقهية الكبرى "الضرورات تبيح المحظورات"، وعليها يُبنى كثير من أحكام النوازل الطبية المعاصرة التي تبيح ما كان أصله محظورًا عند تحقق الضرورة الملجئة وانحصار العلاج فيها، كإباحة زراعة عضو لإنقاذ نفس معصومة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'قرارات مجمع الفقه الإسلامي الدولي — القرار رقم 26 (1/4) بشأن انتفاع الإنسان بأعضاء جسم إنسان آخر، جدة 1408هـ/1988م', 1);
  END IF;

  -- 3) أحكام المريض
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='9d8de0cb-addc-46f7-bdb9-112fa88246a2' AND title='أحكام المريض في العبادات') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أحكام المريض في العبادات', 'تعريف موجز بأبرز الرخص والأحكام الفقهية الخاصة بالمريض في الطهارة والصلاة والصيام', '9d8de0cb-addc-46f7-bdb9-112fa88246a2', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'رخص المريض في الطهارة والصلاة والصيام', 'خفف الشرع عن المريض في العبادات رفعًا للحرج ومراعاة لضعفه، ومن أبرز هذه الرخص: في الطهارة، يجوز للمريض التيمم بدل الوضوء أو الغسل إذا خشي من استعمال الماء زيادة المرض أو تأخر الشفاء. وفي الصلاة، يصلي المريض قائمًا إن استطاع ولو معتمدًا على شيء، فإن عجز صلى قاعدًا، فإن عجز صلى على جنبه مستقبل القبلة، فإن عجز أومأ بالركوع والسجود برأسه، فإن عجز عن الإيماء أجرى أفعال الصلاة على قلبه ولا تسقط عنه ما دام عقله ثابتًا. وفي الصيام، من كان مرضه مما يُرجى برؤه أفطر وقضى عدد الأيام التي أفطرها بعد الشفاء، ومن كان مرضه مزمنًا لا يُرجى برؤه أطعم عن كل يوم مسكينًا بدلًا من القضاء. وهذه الرخص كلها مبنية على قاعدة رفع الحرج عن المكلف عند العجز الحقيقي، لا مجرد المشقة اليسيرة المحتملة.', 1),
    (v_lesson, 'examples', 'أصل الرخصة في الصيام من القرآن', 'قال تعالى: ﴿فَمَن كَانَ مِنكُم مَّرِيضًا أَوْ عَلَىٰ سَفَرٍ فَعِدَّةٌ مِّنْ أَيَّامٍ أُخَرَ﴾ (البقرة: 184)، وهي الآية الصريحة في ترخيص الفطر للمريض في رمضان مع وجوب القضاء بعد زوال العذر، وعليها قاس الفقهاء سائر رخص المريض في العبادات الأخرى من حيث الأصل: رفع التكليف بقدر العجز مع بقاء أصل الفريضة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الفقه الإسلامي وأدلته — وهبة الزحيلي', 1);
  END IF;

  -- 4) أخلاقيات الممارسة الطبية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='77fc4177-f0ff-46c4-a37a-628fd14cce8d' AND title='أخلاقيات الممارسة الطبية في الفقه الإسلامي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أخلاقيات الممارسة الطبية في الفقه الإسلامي', 'تعريف موجز بأبرز الضوابط الشرعية والأخلاقية الحاكمة لممارسة مهنة الطب', '77fc4177-f0ff-46c4-a37a-628fd14cce8d', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'ضوابط أخلاقيات المهنة الطبية', 'وضع الفقه الإسلامي ضوابط أخلاقية وشرعية تحكم ممارسة مهنة الطب، صيانة لحرمة النفس والبدن التي هي أمانة عند الطبيب. من أبرز هذه الضوابط: أولاً، اشتراط الأهلية العلمية، فلا يجوز لمن لم يتقن علم الطب أن يمارسه. ثانيًا، أخذ إذن المريض أو وليه قبل العلاج إلا في حالات الضرورة الملجئة كفاقد الوعي المهدد بالهلاك. ثالثًا، كتمان سر المريض وعدم إفشاء ما يطلع عليه الطبيب من عيوب أو أمراض إلا لضرورة شرعية معتبرة كدرء ضرر عام. رابعًا، مراعاة ضوابط النظر واللمس بين الطبيب والمريض من غير جنسه، بأن يقتصر على موضع الحاجة الطبية دون زيادة، ويُقدَّم الطبيب من نفس الجنس عند الإمكان. خامسًا، الصدق مع المريض في بيان حالته بما لا يورث يأسًا مفرطًا، والحرص على مصلحته لا مصلحة مادية بحتة. وهذه الضوابط جميعًا تتفرع عن مقصد شرعي واحد هو حفظ النفس وصيانة كرامة الإنسان في أضعف أحواله.', 1),
    (v_lesson, 'examples', 'أصل كتمان سر المريض من السنة', 'قال النبي صلى الله عليه وسلم: «من ستر مسلمًا ستره الله في الدنيا والآخرة» (رواه مسلم 2699 عن أبي هريرة رضي الله عنه)، وهو الأصل النبوي الذي يُستدل به على وجوب كتمان الطبيب لأسرار مرضاه وعيوبهم التي يطّلع عليها بحكم مهنته، إذ المريض في أشد الحاجة إلى من يستر حاله لا من يفشيه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أحكام الجراحة الطبية والآثار المترتبة عليها — محمد المختار الشنقيطي', 1);
  END IF;

  -- تحديث حالة التصنيفات الأربعة إلى منشور بعد اكتمال محتواها
  UPDATE categories SET status='published'
  WHERE id IN (
    '5e062cd0-f3f4-435d-82d0-4cd4dde5527e', '2fa6b72a-2c47-4b37-bb5c-f4f744a1fbe7',
    '9d8de0cb-addc-46f7-bdb9-112fa88246a2', '77fc4177-f0ff-46c4-a37a-628fd14cce8d'
  );
END $$;
